mapper.insert:
INSERT INTO weekly_work_approval_log (
    weekly_work_id, action, from_node, to_node, reviewer_user_id, reviewer_name, comment
)
VALUES (
    #{weeklyWorkId}, #{action}, #{fromNode}, #{toNode}, #{reviewerUserId}, #{reviewerName}, #{comment}
)

mapper.select:
SELECT COUNT(DISTINCT w.user_id) FROM weekly_work w INNER JOIN sys_user u ON u.id = w.user_id
u.is_deleted = FALSE
AND u.tree_path LIKE CONCAT(#{treePathPrefix}, '%')
AND w.week_no = #{weekNo}
AND w.status = #{status}

SELECT w.id, w.unit_id, w.user_id, u.username, u.real_name, w.week_no, w.status, w.work_plan, w.work_content, w.remark, w.current_approval_node, w.current_handler_user_id, w.current_handler_user_name, w.current_flow_order, w.final_approver_user_id, w.last_return_target, w.last_return_comment, w.last_review_by_name, w.last_review_time, w.submit_time, w.approved_time, w.create_time FROM weekly_work w INNER JOIN sys_user u ON u.id = w.user_id
AND w.week_no = #{request.weekNo}
AND w.status = #{request.status}
AND w.user_id = #{request.userId}
AND u.tree_path LIKE CONCAT(#{request.treePathPrefix}, '%')
ORDER BY w.week_no DESC, w.create_time DESC, w.id DESC
